// Reactor — spawned by its own dedicated timer, never mixed into OBSTACLE_TYPES
const REACTOR_TYPE: ObstacleType = {
  id: 'reactor', emoji: '☢️', label: 'Reactor Core',
  doseUv: 999999, color: '#b429f9', flashColor: 'rgba(180,41,249,0.70)', prob: 1,
  instantKill: true,
};

// Min gap (px) between any two obstacles to prevent overlap
const OBS_MIN_GAP = 90;

