// ─────────────────────────────────────────────────────────────
//  ANGULAR COMPONENT
// ─────────────────────────────────────────────────────────────
@Component({
  selector: 'app-radiation-runner',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './radiation-runner.component.html',
  styleUrls: ['./radiation-runner.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class RadiationRunnerComponent implements OnInit, AfterViewInit, OnDestroy {

  @ViewChild('gameCanvas', { static: true }) canvasRef!: ElementRef<HTMLCanvasElement>;
  @ViewChild('flashEl', { static: true }) flashRef!: ElementRef<HTMLDivElement>;

  // ── Public state (template-bound) ──────────────────────────
  loadProgress = 0;
  loadMessage = 'Initialising…';
  isLoaded = false;
  screenState: 'loading' | 'start' | 'playing' | 'dead' = 'loading';

  gaugePercent = 0;
  gaugeIcon = '😊';
  statusText = '😊 Healthy — keep running!';
  statusClass = 'healthy';

  scoreDisplay = '0';
  distDisplay = '0 m';
  hitDisplay = '0';
  events: Array<{ type: string; msg: string; id: number }> = [];

  // Death screen stats
  finalDist = '0 m';
  finalScore = '0';
  finalHit = '0';
  finalJumped = '0';
  finalDose = '0 µSv';
  finalEquiv = '0 chest X-rays';
  lastHitLabel = '';

  guideEntries = GUIDE_ENTRIES;
  obstacleTypes = OBSTACLE_TYPES;

  // Typed as the union so *ngFor + (click) both compile cleanly
  filterOptions: Array<'all' | 'safe' | 'low' | 'medium' | 'high' | 'critical'> =
    ['all', 'safe', 'low', 'medium', 'high', 'critical'];

  activeFilter: 'all' | 'safe' | 'low' | 'medium' | 'high' | 'critical' = 'all';

  isPaused = false;

  // ── Private engine state ────────────────────────────────────
  private ctx!: CanvasRenderingContext2D;
  private gs!: GameState;
  private rafId: number | null = null;
  private audio: HTMLAudioElement | null = null;

  private sheetHappy!: HTMLImageElement;
  private sheetSick!: HTMLImageElement;
  private sheetBg!: HTMLImageElement;

  private toastTimer: ReturnType<typeof setTimeout> | null = null;
  private flashTimer: ReturnType<typeof setTimeout> | null = null;
  private eventId = 0;

  // Derived display constants — computed from actual loaded heights after assets arrive
  private readonly CW = CONFIG.CANVAS_W;
  private readonly CH = CONFIG.CANVAS_H;
  private get DISPLAY_W_HAPPY() {
    return Math.round(CONFIG.FRAME_W / this.actualHappyH * CONFIG.DISPLAY_H_HAPPY);
  }
  private get DISPLAY_W_SICK() {
    return Math.round(CONFIG.FRAME_W / this.actualSickH * CONFIG.DISPLAY_H_SICK);
  }

  constructor(private cdr: ChangeDetectorRef) { }

  ngOnInit() { }

  ngAfterViewInit() {
    const canvas = this.canvasRef.nativeElement;
    this.ctx = canvas.getContext('2d')!;
    this.ctx.imageSmoothingEnabled = false;
    this.bindInput();
    this.loadAllAssets();
  }

  ngOnDestroy() {
    if (this.rafId !== null) cancelAnimationFrame(this.rafId);
    if (this.toastTimer) clearTimeout(this.toastTimer);
    if (this.flashTimer) clearTimeout(this.flashTimer);
    document.removeEventListener('keydown', this.boundKeydown);
    this.stopAudio();
  }

  // ── INPUT ───────────────────────────────────────────────────
  private boundKeydown!: (e: KeyboardEvent) => void;
  private bindInput() {
    this.boundKeydown = (e: KeyboardEvent) => {
      if (['Space', 'ArrowUp'].includes(e.code)) { e.preventDefault(); this.handleJump(); }
      if (e.code === 'KeyP' || e.code === 'Escape') { e.preventDefault(); this.togglePause(); }
      if (e.code === 'KeyR' && this.screenState === 'playing') { e.preventDefault(); this.restartGame(); }
    };
    document.addEventListener('keydown', this.boundKeydown);
  }

  onCanvasPointer() { this.handleJump(); }

  private handleJump() {
    if (this.screenState === 'start') { this.startGame(); return; }
    if (this.screenState === 'dead') { this.restartGame(); return; }
    if (!this.gs?.running || this.gs.dead) return;
    if (this.gs.jumpsLeft > 0) {
      this.gs.velY = this.gs.onGround ? CONFIG.JUMP_VY : CONFIG.DOUBLE_JUMP_VY;
      this.gs.onGround = false;
      this.gs.jumpsLeft--;
      this.pushEvent('jump', '🦘 Jumped!');
    }
  }

  // ── ASSET LOADING ───────────────────────────────────────────
  private async loadAllAssets() {
    try {
      this.setLoad(5, 'Loading background…');
      this.sheetBg = await this.loadImage(ASSET_PATHS.BG);
      console.log('BG loaded:', this.sheetBg.width, 'x', this.sheetBg.height);

      this.setLoad(40, 'Loading happy monkey…');
      this.sheetHappy = await this.loadImage(ASSET_PATHS.HAPPY);
      console.log('Happy loaded:', this.sheetHappy.width, 'x', this.sheetHappy.height);

      this.setLoad(80, 'Loading sick monkey…');
      this.sheetSick = await this.loadImage(ASSET_PATHS.SICK);
      console.log('Sick loaded:', this.sheetSick.width, 'x', this.sheetSick.height);

      // Read actual dimensions from the loaded images — no hardcoding required
      this.actualBgW = this.sheetBg.width;
      this.actualBgH = this.sheetBg.height;
      this.actualHappyH = this.sheetHappy.height;
      this.actualSickH = this.sheetSick.height;

      this.setLoad(100, 'Ready!');
      await new Promise(r => setTimeout(r, 250));

      this.isLoaded = true;
      this.screenState = 'start';
      this.drawStartFrame();
      this.cdr.markForCheck();
    } catch (err) {
      console.error('Sprite load failed:', err);
      this.setLoad(0, '❌ Could not load sprites — check asset paths in browser console.');
      this.cdr.markForCheck();
    }
  }

  // Actual dimensions read from files (override CONFIG values after load)
  private actualBgW = CONFIG.BG_TOTAL_W;
  private actualBgH = CONFIG.BG_SRC_H;
  private actualHappyH = CONFIG.HAPPY_SRC_H;
  private actualSickH = CONFIG.SICK_SRC_H;

  // Simple loader — HTMLImageElement works for any width, no 16384px limit
  private loadImage(src: string): Promise<HTMLImageElement> {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = () => reject(new Error(`Failed to load: ${src}`));
      img.src = src;
    });
  }

  private setLoad(pct: number, msg: string) {
    this.loadProgress = pct;
    this.loadMessage = msg;
    this.cdr.markForCheck();
  }

  // ── GAME FLOW ───────────────────────────────────────────────
  startGame() {
    this.initState();
    this.isPaused = false;
    this.gs.running = true;
    this.gs.lastTS = performance.now();
    this.screenState = 'playing';
    this.cdr.markForCheck();
    this.startAudio();
    this.rafId = requestAnimationFrame((ts) => this.loop(ts));
  }

  togglePause() {
    if (this.screenState !== 'playing') return;
    this.isPaused = !this.isPaused;
    if (this.isPaused) {
      this.gs.running = false;
      this.pauseAudio();
      this.renderPauseScreen();
    } else {
      this.gs.running = true;
      this.gs.lastTS = performance.now();
      this.resumeAudio();
    }
    this.cdr.markForCheck();
  }

  onRestartClick() {
    this.stopAudio();
    this.restartGame();
  }

  private startAudio() {
    if (!this.audio) {
      this.audio = new Audio(AUDIO_DATA);
      this.audio.loop = true;
      this.audio.volume = 0.45;
    }
    this.audio.currentTime = 0;
    this.audio.play().catch(() => { }); // autoplay may be blocked — silent fail
  }

  private pauseAudio() { this.audio?.pause(); }
  private resumeAudio() { this.audio?.play().catch(() => { }); }
  private stopAudio() { if (this.audio) { this.audio.pause(); this.audio.currentTime = 0; } }

  private renderPauseScreen() {
    const ctx = this.ctx;
    ctx.save();
    ctx.fillStyle = 'rgba(10,8,30,0.72)';
    ctx.fillRect(0, 0, this.CW, this.CH);
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 42px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('⏸  PAUSED', this.CW / 2, this.CH / 2 - 18);
    ctx.font = '18px sans-serif';
    ctx.fillStyle = '#a29bfe';
    ctx.fillText('Press P or tap ⏸ to resume', this.CW / 2, this.CH / 2 + 22);
    ctx.restore();
  }

  restartGame() {
    this.events = [];
    this.isPaused = false;
    this.stopAudio();
    this.startGame();
  }

  private initState() {
    this.gs = {
      running: false, dead: false,
      monkeyY: this.groundedY(false),
      velY: 0, onGround: true, jumpsLeft: 2,
      frameIdx: 0, frameAccum: 0, isSick: false,
      bgOffset: 0,
      obstacles: [], nextObstacleIn: 2.0, nextReactorIn: 3.5,
      speed: CONFIG.BASE_SPEED,
      score: 0, distance: 0,
      obstaclesHit: 0, obstaclesJumped: 0,
      totalDose: 0, gaugePercent: 0,
      elapsed: 0, lastTS: 0,
      lastHitLabel: '',
      events: [], eventId: 0,
    };
    this.gaugePercent = 0;
    this.gaugeIcon = '😊';
    this.statusText = '😊 Healthy — keep running!';
    this.statusClass = 'healthy';
    this.scoreDisplay = '0';
    this.distDisplay = '0 m';
    this.hitDisplay = '0';
    this.events = [];
  }

  // ── LOOP ────────────────────────────────────────────────────
  private loop(ts: number) {
    const dt = Math.min((ts - this.gs.lastTS) / 1000, 0.05);
    this.gs.lastTS = ts;
    if (this.gs.running && !this.gs.dead && !this.isPaused) {
      this.update(dt);
      this.render();
    }
    if (!this.gs.dead) {
      this.rafId = requestAnimationFrame((t) => this.loop(t));
    }
  }

  // ── UPDATE ──────────────────────────────────────────────────
  private update(dt: number) {
    const gs = this.gs;
    gs.elapsed += dt;
    gs.distance += gs.speed * dt / 60;
    gs.score += Math.floor(gs.speed * dt / 10);
    gs.speed = Math.min(CONFIG.MAX_SPEED, CONFIG.BASE_SPEED + gs.elapsed * CONFIG.SPEED_INCR);

    // Physics
    if (!gs.onGround) { gs.velY += CONFIG.GRAVITY * dt; gs.monkeyY += gs.velY * dt; }
    const floorY = this.groundedY(gs.isSick);
    if (gs.monkeyY >= floorY) {
      gs.monkeyY = floorY; gs.velY = 0; gs.onGround = true; gs.jumpsLeft = 2;
    }

    // Animation frame
    gs.frameAccum += dt;
    if (gs.frameAccum >= 1 / CONFIG.ANIM_FPS) {
      gs.frameAccum -= 1 / CONFIG.ANIM_FPS;
      gs.frameIdx = (gs.frameIdx + 1) % CONFIG.TOTAL_FRAMES;
    }

    // BG scroll — wrap against actual loaded image width
    gs.bgOffset = (gs.bgOffset + gs.speed * dt) % this.actualBgW;

    // ── Spawn normal obstacles ──────────────────────────────
    gs.nextObstacleIn -= dt;
    if (gs.nextObstacleIn <= 0) {
      this.spawnObstacle();
      const mg = Math.max(0.8, 2.0 - gs.elapsed * 0.006);
      gs.nextObstacleIn = mg + Math.random() * 1.8;
    }

    // ── Spawn reactor (dedicated timer, always fires) ─────
    gs.nextReactorIn -= dt;
    if (gs.nextReactorIn <= 0) {
      this.spawnReactor();
      // Reactor appears every 3.5–5.5 s regardless of speed
      gs.nextReactorIn = 3.5 + Math.random() * 2.0;
    }

    // Hitbox (inner 50% of sprite)
    const dH = gs.isSick ? CONFIG.DISPLAY_H_SICK : CONFIG.DISPLAY_H_HAPPY;
    const dW = gs.isSick ? this.DISPLAY_W_SICK : this.DISPLAY_W_HAPPY;
    const mL = CONFIG.MONKEY_X + dW * 0.22;
    const mR = CONFIG.MONKEY_X + dW * 0.72;
    const mT = gs.monkeyY + dH * 0.20;
    const mB = gs.monkeyY + dH * 0.90;

    for (let i = gs.obstacles.length - 1; i >= 0; i--) {
      const o = gs.obstacles[i];
      if (o.hit) { o.anim -= dt; if (o.anim <= 0) gs.obstacles.splice(i, 1); continue; }
      o.x -= gs.speed * dt;

      if (!o.scored) {
        if (mR > o.x + 5 && mL < o.x + o.w - 5 && mB > o.y + 6 && mT < o.y + o.h) {
          // HIT
          o.hit = true; o.anim = 0.9; o.scored = true;
          gs.obstaclesHit++;
          this.addRadiation(o.type);
          this.flashScreen(o.type.flashColor);
          this.pushEvent('hit', `☢ ${o.type.label} +${this.fmtDose(o.type.doseUv)}`);
        } else if (o.x + o.w < mL - 5) {
          o.scored = true;
          gs.obstaclesJumped++;
          gs.score += 50;
          this.pushEvent('jump', `✅ Dodged ${o.type.emoji} +50pts`);
          this.flashScreen('rgba(0,184,148,0.28)');
        }
      }
      if (o.x < -o.w - 20) gs.obstacles.splice(i, 1);
    }

    gs.isSick = gs.gaugePercent >= CONFIG.SICK_AT;

    // Update template-bound values (throttled to avoid excessive CD)
    if (Math.floor(gs.elapsed * 10) % 2 === 0) this.syncHUD();
    if (gs.gaugePercent >= 100) this.triggerDeath();
  }

  // ── SPAWN HELPERS ───────────────────────────────────────────
  /** Returns a safe X start position that doesn't overlap any existing obstacle */
  private safeSpawnX(w: number): number {
    const base = this.CW + 40;
    // Check if any obstacle is within OBS_MIN_GAP of the right edge
    const rightmost = this.gs.obstacles.reduce((max, o) => Math.max(max, o.x + o.w), 0);
    // If last obstacle is still on screen (x > 0) and close to right edge, push further right
    if (rightmost > this.CW - OBS_MIN_GAP) {
      return rightmost + OBS_MIN_GAP + 10;
    }
    return base;
  }

  private spawnObstacle() {
    const type = this.pickObstacleType();
    // Plane flies a bit higher; all others sit on the ground
    const isPlane = type.id === 'plane';
    const w = isPlane ? 60 : 54;
    const h = isPlane ? 48 : 54;
    const y = isPlane ? CONFIG.GROUND_Y - 95 : CONFIG.GROUND_Y - 54;
    const x = this.safeSpawnX(w);
    this.gs.obstacles.push({ x, y, w, h, type, hit: false, scored: false, anim: 0 });
    this.pushEvent('spawn', `${type.emoji} ${type.label} incoming!`);
  }

  private spawnReactor() {
    const w = 62, h = 62;
    // Reactor floats at a mid-air height — clearly distinct from ground obstacles
    // and from the plane lane. Sits roughly at mid-canvas height.
    const y = CONFIG.GROUND_Y - 60;
    // Find a spawn X that doesn't overlap any existing obstacle
    let x = this.CW + 40;
    let attempts = 0;
    while (attempts < 8) {
      const clash = this.gs.obstacles.some(o =>
        Math.abs(o.x - x) < (o.w / 2 + w / 2 + OBS_MIN_GAP)
      );
      if (!clash) break;
      x += OBS_MIN_GAP + 20;
      attempts++;
    }
    this.gs.obstacles.push({ x, y, w, h, type: REACTOR_TYPE, hit: false, scored: false, anim: 0 });
    this.pushEvent('spawn', `☢️ Reactor Core! DODGE IT!`);
  }

  private pickObstacleType(): ObstacleType {
    let r = Math.random();
    for (const t of OBSTACLE_TYPES) {
      r -= t.prob;
      if (r <= 0) return t;
    }
    return OBSTACLE_TYPES[0];
  }

  // ── RADIATION ───────────────────────────────────────────────
  private addRadiation(type: ObstacleType) {
    if (type.instantKill) {
      this.gs.totalDose = CONFIG.MAX_DOSE;
      this.gs.gaugePercent = 100;
      this.gs.lastHitLabel = type.label;
      this.triggerDeath(true);
      return;
    }
    this.gs.totalDose = Math.min(CONFIG.MAX_DOSE, this.gs.totalDose + type.doseUv);
    this.gs.gaugePercent = (this.gs.totalDose / CONFIG.MAX_DOSE) * 100;
    this.gs.lastHitLabel = type.label;
  }

  private fmtDose(uv: number): string {
    if (uv < 1) return uv.toFixed(2) + ' µSv';
    if (uv < 1000) return uv.toFixed(1) + ' µSv';
    if (uv < 1e6) return (uv / 1000).toFixed(2) + ' mSv';
    return (uv / 1e6).toFixed(3) + ' Sv';
  }

  // ── RENDER ──────────────────────────────────────────────────
  private render() {
    const ctx = this.ctx;
    ctx.imageSmoothingEnabled = false;
    ctx.clearRect(0, 0, this.CW, this.CH);
    this.renderBG();

    if (this.gs.gaugePercent > 40) {
      ctx.save();
      ctx.globalAlpha = ((this.gs.gaugePercent - 40) / 60) * 0.28;
      ctx.fillStyle = '#e74c3c';
      ctx.fillRect(0, 0, this.CW, this.CH);
      ctx.restore();
    }

    for (const o of this.gs.obstacles) this.renderObstacle(o);
    this.renderMonkey();

    // Speed strip
    const spd = (this.gs.speed - CONFIG.BASE_SPEED) / (CONFIG.MAX_SPEED - CONFIG.BASE_SPEED);
    ctx.fillStyle = `rgba(162,155,254,${0.12 + spd * 0.3})`;
    ctx.fillRect(this.CW - 8, this.CH - Math.floor(spd * this.CH), 6, Math.floor(spd * this.CH));
  }

  private renderBG() {
    if (!this.sheetBg) return;
    const ctx = this.ctx;
    const bgW = this.actualBgW;   // real width read from loaded image
    const bgH = this.actualBgH;   // real height read from loaded image
    const scaleY = this.CH / bgH;  // scale BG height to canvas height

    ctx.imageSmoothingEnabled = false;
    ctx.save();
    ctx.beginPath(); ctx.rect(0, 0, this.CW, this.CH); ctx.clip();

    let drawX = 0;
    let srcX = Math.floor(this.gs.bgOffset) % bgW;
    while (drawX < this.CW) {
      const srcChunk = Math.min(bgW - srcX, this.CW - drawX);
      const dstChunk = srcChunk * scaleY;
      ctx.drawImage(this.sheetBg, srcX, 0, srcChunk, bgH, drawX, 0, dstChunk, this.CH);
      drawX += dstChunk;
      srcX = 0;
      if (drawX >= this.CW) break;
    }
    ctx.restore();
  }

  private renderMonkey() {
    const gs = this.gs;
    const sheet = gs.isSick ? this.sheetSick : this.sheetHappy;
    if (!sheet) return;
    // Use actual loaded heights, not CONFIG — so replacing sprites just works
    const srcH = gs.isSick ? this.actualSickH : this.actualHappyH;
    const dH = gs.isSick ? CONFIG.DISPLAY_H_SICK : CONFIG.DISPLAY_H_HAPPY;
    const dW = gs.isSick ? this.DISPLAY_W_SICK : this.DISPLAY_W_HAPPY;
    const sx = gs.frameIdx * CONFIG.FRAME_W;
    const ctx = this.ctx;

    // Shadow
    if (gs.onGround) {
      ctx.save();
      ctx.globalAlpha = 0.18;
      ctx.fillStyle = '#000';
      ctx.beginPath();
      ctx.ellipse(CONFIG.MONKEY_X + dW / 2, CONFIG.GROUND_Y + 5, dW * 0.38, 7, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    }

    ctx.save();
    ctx.imageSmoothingEnabled = false;
    if (!gs.onGround) {
      ctx.translate(CONFIG.MONKEY_X + dW / 2, gs.monkeyY + dH / 2);
      ctx.scale(0.93, 1.07);
      ctx.translate(-(CONFIG.MONKEY_X + dW / 2), -(gs.monkeyY + dH / 2));
    }
    ctx.drawImage(sheet, sx, 0, CONFIG.FRAME_W, srcH, CONFIG.MONKEY_X, gs.monkeyY, dW, dH);
    ctx.restore();
  }

  private renderObstacle(o: Obstacle) {
    const ctx = this.ctx;
    ctx.save();

    if (o.hit) {
      // Burst animation — spins and fades out
      const p = 1 - o.anim / 0.9;
      ctx.globalAlpha = 1 - p;
      ctx.translate(o.x + o.w / 2, o.y + o.h / 2);
      ctx.rotate(p * Math.PI * 2.2);
      ctx.scale(1 + p * 1.8, 1 + p * 1.8);
      ctx.font = `${o.w}px serif`;
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      ctx.fillText(o.type.emoji, 0, 0);
      ctx.globalAlpha = (1 - p) * 0.85;
      ctx.strokeStyle = o.type.color; ctx.lineWidth = 2.5;
      ctx.beginPath();
      for (let i = 0; i < 8; i++) {
        const a = (i / 8) * Math.PI * 2;
        ctx.moveTo(0, 0);
        ctx.lineTo(Math.cos(a) * (18 + p * 30), Math.sin(a) * (18 + p * 30));
      }
      ctx.stroke();
      ctx.globalAlpha = (1 - p) * 0.95;
      ctx.fillStyle = '#e74c3c';
      ctx.font = `${10 + p * 16}px serif`;
      ctx.fillText('☢', 0, -(12 + p * 20));

    } else {
      // ── IDLE — fully opaque, clearly visible ──────────────────
      const cx = o.x + o.w / 2;
      const cy = o.y + o.h / 2;
      const now = Date.now();
      const pulse = Math.sin(now / 320) * 0.4 + 0.6;  // 0.2–1.0

      if (o.type.id === 'reactor') {
        // ═══ REACTOR — special high-visibility rendering ════════

        // Outer warning ring — large pulsing halo
        const haloR = o.w * 0.85 + pulse * 14;
        ctx.globalAlpha = 0.22 + pulse * 0.18;
        ctx.strokeStyle = '#b429f9';
        ctx.lineWidth = 4;
        ctx.beginPath(); ctx.arc(cx, cy, haloR, 0, Math.PI * 2); ctx.stroke();

        // Second ring
        ctx.globalAlpha = 0.15 + pulse * 0.12;
        ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(cx, cy, haloR + 12, 0, Math.PI * 2); ctx.stroke();

        // Dark filled circle background
        ctx.globalAlpha = 0.90;
        ctx.fillStyle = 'rgba(20, 0, 30, 0.90)';
        ctx.beginPath(); ctx.arc(cx, cy, o.w * 0.6, 0, Math.PI * 2); ctx.fill();

        // Neon border circle
        ctx.globalAlpha = 1;
        ctx.strokeStyle = '#b429f9';
        ctx.lineWidth = 3;
        ctx.shadowColor = '#b429f9';
        ctx.shadowBlur = 10 + pulse * 16;
        ctx.beginPath(); ctx.arc(cx, cy, o.w * 0.6, 0, Math.PI * 2); ctx.stroke();

        // Emoji — large and crisp
        ctx.shadowBlur = 8 + pulse * 8;
        ctx.globalAlpha = 1;
        ctx.font = `${o.w + 4}px serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(o.type.emoji, cx, cy + 2);

        // Reset shadow
        ctx.shadowBlur = 0;
        ctx.shadowColor = 'transparent';

        // INSTANT KILL badge — always visible, bold red
        ctx.font = 'bold 11px sans-serif';
        ctx.textBaseline = 'middle';
        const badgeTxt = '☠ INSTANT KILL';
        const badgeW = ctx.measureText(badgeTxt).width + 14;
        const badgeY = o.y - 22;
        ctx.globalAlpha = 0.95;
        ctx.fillStyle = '#b429f9';
        ctx.beginPath();
        (ctx as any).roundRect(cx - badgeW / 2, badgeY - 9, badgeW, 18, 5);
        ctx.fill();
        ctx.globalAlpha = 1;
        ctx.fillStyle = '#fff';
        ctx.fillText(badgeTxt, cx, badgeY);

        // Warning track on ground under reactor — so player knows where it will land height-wise
        ctx.globalAlpha = 0.35 + pulse * 0.15;
        ctx.strokeStyle = '#b429f9';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.beginPath();
        ctx.moveTo(cx, cy + o.h * 0.5);
        ctx.lineTo(cx, CONFIG.GROUND_Y);
        ctx.stroke();
        ctx.setLineDash([]);

        // Approaching warning
        const dist = o.x - (CONFIG.MONKEY_X + (this.gs.isSick ? this.DISPLAY_W_SICK : this.DISPLAY_W_HAPPY));
        if (dist < 260 && dist > -20) {
          ctx.save();
          const alpha = Math.max(0, 1 - dist / 260);
          ctx.globalAlpha = alpha;
          ctx.font = 'bold 13px sans-serif';
          ctx.fillStyle = '#e056fd';
          ctx.textBaseline = 'bottom';
          ctx.textAlign = 'center';
          // Flash text
          if (Math.sin(now / 120) > 0) {
            ctx.fillText('⚠ REACTOR — JUMP!', cx, o.y - 32);
          }
          ctx.restore();
        }

      } else {
        // ═══ NORMAL OBSTACLE ═══════════════════════════════════

        // 1. Dark pill background
        const pillW = o.w + 14;
        const pillH = o.h + 10;
        ctx.globalAlpha = 0.85;
        ctx.fillStyle = 'rgba(8, 6, 18, 0.80)';
        ctx.beginPath();
        (ctx as any).roundRect(cx - pillW / 2, cy - pillH / 2, pillW, pillH, 10);
        ctx.fill();

        // 2. Coloured border
        ctx.globalAlpha = 1;
        ctx.strokeStyle = o.type.color;
        ctx.lineWidth = 2.5;
        ctx.beginPath();
        (ctx as any).roundRect(cx - pillW / 2, cy - pillH / 2, pillW, pillH, 10);
        ctx.stroke();

        // 3. Glow
        ctx.shadowColor = o.type.color;
        ctx.shadowBlur = 5 + pulse * 7;

        // 4. Emoji at full opacity
        ctx.globalAlpha = 1;
        ctx.font = `${o.w}px serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(o.type.emoji, cx, cy + 2);

        // 5. Kill shadow
        ctx.shadowBlur = 0;
        ctx.shadowColor = 'transparent';

        // 6. Dose badge
        const doseText = o.type.doseUv < 1
          ? `${o.type.doseUv.toFixed(2)}µSv`
          : o.type.doseUv < 1000
            ? `${o.type.doseUv.toFixed(0)}µSv`
            : `${(o.type.doseUv / 1000).toFixed(1)}mSv`;

        ctx.font = 'bold 10px sans-serif';
        ctx.textBaseline = 'middle';
        const badgeW = ctx.measureText(doseText).width + 12;
        const badgeY = o.y - 18;
        ctx.globalAlpha = 0.92;
        ctx.fillStyle = o.type.color;
        ctx.beginPath();
        (ctx as any).roundRect(cx - badgeW / 2, badgeY - 8, badgeW, 16, 4);
        ctx.fill();
        ctx.globalAlpha = 1;
        ctx.fillStyle = '#000';
        ctx.textAlign = 'center';
        ctx.fillText(doseText, cx, badgeY);

        // 7. Proximity warning
        const dist = o.x - (CONFIG.MONKEY_X + (this.gs.isSick ? this.DISPLAY_W_SICK : this.DISPLAY_W_HAPPY));
        if (dist < 180 && dist > -20) {
          ctx.save();
          ctx.globalAlpha = Math.max(0, 1 - dist / 180);
          ctx.font = 'bold 11px sans-serif';
          ctx.fillStyle = '#fff';
          ctx.textBaseline = 'bottom';
          ctx.textAlign = 'center';
          ctx.fillText(`⚠ ${o.type.label}`, cx, o.y - 26);
          ctx.restore();
        }
      }
    }

    ctx.restore();
  }

  // ── HUD SYNC ────────────────────────────────────────────────
  private syncHUD() {
    const p = this.gs.gaugePercent;
    this.gaugePercent = p;
    this.scoreDisplay = this.gs.score.toLocaleString();
    this.distDisplay = Math.floor(this.gs.distance) + ' m';
    this.hitDisplay = String(this.gs.obstaclesHit);
    this.lastHitLabel = this.gs.lastHitLabel;

    if (p < 25) { this.gaugeIcon = '😊'; this.statusText = '😊 Healthy — keep running!'; this.statusClass = 'healthy'; }
    else if (p < 50) { this.gaugeIcon = '😵'; this.statusText = '😵 Feeling confused…'; this.statusClass = 'confused'; }
    else if (p < 80) { this.gaugeIcon = '🤢'; this.statusText = '🤢 Radiation sickness!'; this.statusClass = 'sick'; }
    else { this.gaugeIcon = '☠'; this.statusText = '☠ Critical — almost dead!'; this.statusClass = 'critical'; }

    this.cdr.markForCheck();
  }

  // ── DEATH ───────────────────────────────────────────────────
  private triggerDeath(instantKill = false) {
    this.gs.dead = this.gs.running = false;
    if (this.rafId !== null) { cancelAnimationFrame(this.rafId); this.rafId = null; }
    this.stopAudio();

    this.finalDist = Math.floor(this.gs.distance) + ' m';
    this.finalScore = this.gs.score.toLocaleString();
    this.finalHit = String(this.gs.obstaclesHit);
    this.finalJumped = String(this.gs.obstaclesJumped);
    this.finalDose = this.fmtDose(this.gs.totalDose);
    this.finalEquiv = Math.round(this.gs.totalDose / 100) + ' chest X-rays';

    this.screenState = 'dead';
    this.flashScreen('rgba(214,48,49,0.55)');
    this.cdr.markForCheck();
  }

  // ── START FRAME ─────────────────────────────────────────────
  private drawStartFrame() {
    if (!this.sheetHappy || !this.sheetBg) return;
    const ctx = this.ctx;
    const bgH = this.actualBgH;
    const bgW = this.actualBgW;
    const scaleY = this.CH / bgH;
    ctx.imageSmoothingEnabled = false;
    // Draw first visible portion of BG
    const srcChunk = Math.min(bgW, Math.ceil(this.CW / scaleY));
    ctx.drawImage(this.sheetBg, 0, 0, srcChunk, bgH, 0, 0, srcChunk * scaleY, this.CH);
    // Draw frame 0 of happy monkey
    const dH = CONFIG.DISPLAY_H_HAPPY, dW = this.DISPLAY_W_HAPPY;
    ctx.drawImage(
      this.sheetHappy, 0, 0, CONFIG.FRAME_W, this.actualHappyH,
      CONFIG.MONKEY_X, this.groundedY(false), dW, dH
    );
  }

  // ── HELPERS ─────────────────────────────────────────────────
  private groundedY(sick: boolean): number {
    if (sick) return CONFIG.GROUND_Y - CONFIG.DISPLAY_H_SICK + CONFIG.GROUND_SINK_SICK;
    return CONFIG.GROUND_Y - CONFIG.DISPLAY_H_HAPPY + CONFIG.GROUND_SINK_HAPPY;
  }

  private flashScreen(color: string) {
    const el = this.flashRef.nativeElement;
    el.style.background = color; el.style.opacity = '1';
    if (this.flashTimer) clearTimeout(this.flashTimer);
    this.flashTimer = setTimeout(() => { el.style.opacity = '0'; }, 160);
  }

  private pushEvent(type: string, msg: string) {
    this.events = [{ type, msg, id: this.eventId++ }, ...this.events].slice(0, 4);
    this.cdr.markForCheck();
  }

  // ── GUIDE FILTER ────────────────────────────────────────────
  setFilter(f: typeof this.activeFilter) { this.activeFilter = f; }

  get filteredGuide(): GuideEntry[] {
    if (this.activeFilter === 'all') return GUIDE_ENTRIES;
    return GUIDE_ENTRIES.filter(e => e.category === this.activeFilter);
  }

  getDoseBarWidth(doseValue: number): string {
    // Log scale from 0.01 to 1,000,000
    const pct = Math.min(100, (Math.log10(doseValue + 0.01) / Math.log10(1000001)) * 100);
    return pct.toFixed(1) + '%';
  }

  trackEvent(_: number, ev: { id: number }): number { return ev.id; }
}

